import React, { useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { addRegistration, convertRegistrationToStudent, addClass } from '../store/slices/admissionSlice';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';

const inp = { width:'100%', padding:'10px 12px', border:'1.5px solid #E5E7EB', borderRadius:9, fontSize:13, outline:'none', fontFamily:'inherit', background:'#fff', boxSizing:'border-box' };
const lbl = { display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 };

export default function Registration() {
  const dispatch       = useDispatch();
  const navigate       = useNavigate();
  const registrations  = useSelector(s => s.admission.registrations);
  const classes        = useSelector(s => s.admission.classes);

  const [showAdd,      setShowAdd]      = useState(false);
  const [showAddClass, setShowAddClass] = useState(false);
  const [newClass,     setNewClass]     = useState('');
  const [selected,     setSelected]     = useState(null);
  const [form, setForm] = useState({ name:'', parent:'', phone:'', email:'', class_:'', prevSchool:'', regFee:'500', feePaid:false });

  const handleAdd = (e) => {
    e.preventDefault();
    dispatch(addRegistration({ ...form, fee: parseInt(form.regFee)||500, paid: form.feePaid }));
    toast.success(`✅ Registration created for ${form.name}`);
    setShowAdd(false);
    setForm({ name:'', parent:'', phone:'', email:'', class_:'', prevSchool:'', regFee:'500', feePaid:false });
  };

  const handleAddClass = () => {
    if (!newClass.trim()) return;
    if (classes.includes(newClass.trim())) { toast.error('Class already exists!'); return; }
    dispatch(addClass(newClass.trim()));
    toast.success(`Class "${newClass.trim()}" added!`);
    setNewClass('');
    setShowAddClass(false);
  };

  const handleConvert = (reg) => {
    dispatch(convertRegistrationToStudent(reg.id));
    toast.success(`🎓 ${reg.name} admitted as student! Check Students module.`);
    setSelected(null);
    setTimeout(() => navigate('/students'), 1200);
  };

  const pending   = registrations.filter(r => r.status === 'pending').length;
  const converted = registrations.filter(r => r.status === 'converted').length;
  const feePaid   = registrations.filter(r => r.paid).length;

  return (
    <div>
      {/* Header */}
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:18}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>Registration Management</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>Register students before formal admission</p>
        </div>
        <div style={{display:'flex',gap:10}}>
          <button onClick={()=>setShowAddClass(true)} style={{padding:'9px 14px',border:'1.5px solid #1E1B4B',borderRadius:9,background:'#EDE9F8',color:'#1E1B4B',fontSize:12,fontWeight:700,cursor:'pointer'}}>+ Add Class</button>
          <button onClick={()=>setShowAdd(true)} style={{padding:'9px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ New Registration</button>
        </div>
      </div>

      {/* Pipeline banner */}
      <div style={{display:'flex',alignItems:'center',gap:8,padding:'12px 16px',background:'#EDE9F8',borderRadius:12,marginBottom:16,fontSize:12,color:'#1E1B4B',fontWeight:600}}>
        <span>📞 Enquiry</span>
        <span style={{color:'#A78BFA',fontSize:16}}>→</span>
        <span style={{fontWeight:800,textDecoration:'underline'}}>📄 Registration</span>
        <span style={{color:'#A78BFA',fontSize:16}}>→</span>
        <span>🎓 Admission</span>
        <span style={{marginLeft:'auto',fontSize:11,fontWeight:500,color:'#6B52B0'}}>Click "Convert to Admission" to admit a student</span>
      </div>

      {/* Stats */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:12,marginBottom:18}}>
        {[['Total',registrations.length,'#EDE9F8','#1E1B4B'],['Pending',pending,'#FEF3C7','#92400E'],['Converted',converted,'#D1FAE5','#065F46'],['Fee Paid',feePaid,'#DBEAFE','#1E40AF']].map(([l,v,bg,c])=>(
          <div key={l} style={{padding:'14px',background:bg,borderRadius:12,textAlign:'center'}}>
            <div style={{fontSize:24,fontWeight:800,color:c,lineHeight:1}}>{v}</div>
            <div style={{fontSize:11,color:c,marginTop:4,opacity:.8,fontWeight:600}}>{l}</div>
          </div>
        ))}
      </div>

      {/* Table */}
      <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
          <thead><tr style={{background:'#F9FAFB'}}>
            {['Reg No','Student','Parent / Phone','Class','From Enquiry','Reg Fee','Date','Status','Actions'].map(h=>(
              <th key={h} style={{padding:'10px 12px',textAlign:'left',color:'#6B7280',fontSize:10,fontWeight:700,textTransform:'uppercase',borderBottom:'1px solid #E5E7EB',whiteSpace:'nowrap'}}>{h}</th>
            ))}
          </tr></thead>
          <tbody>
            {registrations.length === 0 && (
              <tr><td colSpan={9} style={{padding:40,textAlign:'center',color:'#9CA3AF'}}>
                <div style={{fontSize:32,marginBottom:8}}>📄</div>
                No registrations yet. Convert an enquiry or add new registration.
              </td></tr>
            )}
            {registrations.map(r => (
              <tr key={r.id} style={{borderBottom:'0.5px solid #F3F4F6',transition:'background .1s'}}
                onMouseEnter={e=>e.currentTarget.style.background='#F5F3FF'}
                onMouseLeave={e=>e.currentTarget.style.background=''}>
                <td style={{padding:'10px 12px',fontFamily:'monospace',fontSize:11,color:'#9CA3AF'}}>{r.no}</td>
                <td style={{padding:'10px 12px'}}>
                  <div style={{fontWeight:700,color:'#111827'}}>{r.name}</div>
                  {r.fromEnquiry && <div style={{fontSize:10,color:'#7C3AED',marginTop:2}}>📞 From enquiry {r.enquiryNo}</div>}
                </td>
                <td style={{padding:'10px 12px'}}><div style={{fontWeight:500}}>{r.parent}</div><div style={{fontSize:10,color:'#9CA3AF'}}>{r.phone}</div></td>
                <td style={{padding:'10px 12px',color:'#374151',fontWeight:500}}>{r.class_||'—'}</td>
                <td style={{padding:'10px 12px'}}>
                  {r.enquiryNo
                    ? <span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#EDE9F8',color:'#1E1B4B',fontWeight:600}}>{r.enquiryNo}</span>
                    : <span style={{color:'#9CA3AF',fontSize:11}}>Direct</span>}
                </td>
                <td style={{padding:'10px 12px'}}>
                  <div style={{fontWeight:700}}>₹{r.fee}</div>
                  <span style={{padding:'1px 6px',borderRadius:10,fontSize:10,background:r.paid?'#D1FAE5':'#FEE2E2',color:r.paid?'#065F46':'#991B1B',fontWeight:600}}>{r.paid?'✓ Paid':'Unpaid'}</span>
                </td>
                <td style={{padding:'10px 12px',color:'#6B7280'}}>{r.date}</td>
                <td style={{padding:'10px 12px'}}>
                  <span style={{padding:'3px 9px',borderRadius:20,fontSize:10,fontWeight:700,background:r.status==='converted'?'#D1FAE5':'#FEF3C7',color:r.status==='converted'?'#065F46':'#92400E'}}>
                    {r.status==='converted'?'✅ Admitted':'⏳ Pending'}
                  </span>
                </td>
                <td style={{padding:'10px 12px'}}>
                  {r.status === 'pending' ? (
                    <button onClick={()=>setSelected(r)}
                      style={{padding:'5px 12px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:7,fontSize:11,fontWeight:700,cursor:'pointer',whiteSpace:'nowrap'}}>
                      → Admit
                    </button>
                  ) : (
                    <button onClick={()=>navigate('/students')}
                      style={{padding:'5px 12px',border:'1px solid #E5E7EB',borderRadius:7,background:'#fff',fontSize:11,cursor:'pointer'}}>View Student</button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <div style={{padding:'10px 14px',borderTop:'0.5px solid #E5E7EB',fontSize:11,color:'#6B7280'}}>
          {registrations.length} total registrations · {converted} admitted as students
        </div>
      </div>

      {/* Convert Confirmation Modal */}
      {selected && (
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:500,display:'flex',alignItems:'center',justifyContent:'center',padding:20}}>
          <div style={{background:'#fff',borderRadius:18,width:460,overflow:'hidden'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div style={{fontWeight:700,fontSize:15}}>🎓 Convert to Admission</div>
              <button onClick={()=>setSelected(null)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <div style={{padding:22}}>
              <div style={{padding:16,background:'#EDE9F8',borderRadius:12,marginBottom:18}}>
                <div style={{fontSize:16,fontWeight:800,color:'#1E1B4B',marginBottom:8}}>{selected.name}</div>
                <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:8,fontSize:12}}>
                  {[['Parent',selected.parent],['Phone',selected.phone],['Class',selected.class_||'—'],['Reg No',selected.no]].map(([k,v])=>(
                    <div key={k}><span style={{color:'#6B7280'}}>{k}: </span><strong>{v}</strong></div>
                  ))}
                </div>
              </div>
              <div style={{padding:'12px 14px',background:'#FEF3C7',borderRadius:10,marginBottom:18,fontSize:12,color:'#92400E'}}>
                ⚠️ This will create a new student record and auto-generate an Admission Number.
                You can update full student details from the Students module.
              </div>
              <div style={{display:'flex',gap:10}}>
                <button onClick={()=>setSelected(null)} style={{flex:1,padding:'11px',border:'1.5px solid #E5E7EB',borderRadius:10,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button onClick={()=>handleConvert(selected)} style={{flex:2,padding:'11px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:10,fontSize:13,fontWeight:800,cursor:'pointer'}}>🎓 Confirm Admission →</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Add Class Modal */}
      {showAddClass && (
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:500,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:420,overflow:'hidden'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div style={{fontWeight:700,fontSize:15}}>+ Add New Class</div>
              <button onClick={()=>setShowAddClass(false)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <div style={{padding:20}}>
              <div style={{marginBottom:14}}><label style={lbl}>Class Name *</label><input value={newClass} onChange={e=>setNewClass(e.target.value)} placeholder="e.g. Class 6, LKG, Nursery" style={inp} autoFocus onKeyDown={e=>e.key==='Enter'&&handleAddClass()}/></div>
              <div style={{marginBottom:16}}>
                <div style={{fontSize:11,fontWeight:700,color:'#6B7280',marginBottom:8}}>Existing Classes:</div>
                <div style={{display:'flex',flexWrap:'wrap',gap:6}}>{classes.map(c=><span key={c} style={{padding:'3px 10px',background:'#EDE9F8',borderRadius:20,fontSize:11,color:'#1E1B4B'}}>{c}</span>)}</div>
              </div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button onClick={()=>setShowAddClass(false)} style={{padding:'9px 18px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button onClick={handleAddClass} style={{padding:'9px 22px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ Add Class</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* New Registration Modal */}
      {showAdd && (
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:500,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:560,maxWidth:'100%',maxHeight:'90vh',overflow:'auto'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center',position:'sticky',top:0,background:'#fff'}}>
              <div style={{fontWeight:700,fontSize:15}}>📄 New Registration</div>
              <button onClick={()=>setShowAdd(false)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <form onSubmit={handleAdd} style={{padding:20}}>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Student Name *</label><input required value={form.name} onChange={e=>setForm({...form,name:e.target.value})} style={inp} autoFocus/></div>
                <div><label style={lbl}>Parent Name *</label><input required value={form.parent} onChange={e=>setForm({...form,parent:e.target.value})} style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Mobile *</label><input required value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})} maxLength={10} style={inp}/></div>
                <div><label style={lbl}>Email</label><input type="email" value={form.email} onChange={e=>setForm({...form,email:e.target.value})} style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr auto',gap:10,alignItems:'end',marginBottom:12}}>
                <div>
                  <label style={lbl}>Class *</label>
                  <select required value={form.class_} onChange={e=>setForm({...form,class_:e.target.value})} style={inp}>
                    <option value="">Select class</option>
                    {classes.map(c=><option key={c}>{c}</option>)}
                  </select>
                  <div style={{fontSize:10,color:'#9CA3AF',marginTop:4}}>Class not in list? Click + to add it</div>
                </div>
                <button type="button" onClick={()=>setShowAddClass(true)} title="Add new class"
                  style={{padding:'10px 16px',border:'1.5px solid #1E1B4B',borderRadius:9,background:'#EDE9F8',color:'#1E1B4B',fontWeight:800,cursor:'pointer',fontSize:18,height:42}}>+</button>
              </div>
              <div style={{marginBottom:12}}><label style={lbl}>Previous School</label><input value={form.prevSchool} onChange={e=>setForm({...form,prevSchool:e.target.value})} placeholder="Optional" style={inp}/></div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:16}}>
                <div><label style={lbl}>Registration Fee (₹)</label><input type="number" value={form.regFee} onChange={e=>setForm({...form,regFee:e.target.value})} style={inp}/></div>
                <div style={{display:'flex',alignItems:'center',gap:10,paddingTop:24}}>
                  <input type="checkbox" id="fp" checked={form.feePaid} onChange={e=>setForm({...form,feePaid:e.target.checked})} style={{width:18,height:18,accentColor:'#1E1B4B',cursor:'pointer'}}/>
                  <label htmlFor="fp" style={{fontSize:13,fontWeight:600,cursor:'pointer',color:'#111827'}}>Fee Paid</label>
                </div>
              </div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button type="button" onClick={()=>setShowAdd(false)} style={{padding:'10px 18px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button type="submit" style={{padding:'10px 24px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>💾 Save Registration</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
